import{_ as a,o as t,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const b=JSON.parse('{"title":"Web to App","description":"","frontmatter":{"title":"Web to App","slug":"web-to-app"},"headers":[],"relativePath":"marketer-hub/web-to-app.md","filePath":"marketer-hub/web-to-app.md"}'),i={name:"marketer-hub/web-to-app.md"};function n(s,e,l,p,h,u){return t(),r("div",null,[...e[0]||(e[0]=[o('<p><em>[Image: 253]</em>.svg &quot;phone-1.svg&quot;)</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Getting users to your app can be a challenge. Journeys helps drive growth and engagement by turning your mobile website into your largest source of app installs. Through smart banners and interstitials, you can promote your app on your mobile website that uses intelligent targeting.</p><h3 id="journeys-use-cases" tabindex="-1">Journeys Use Cases: <a class="header-anchor" href="#journeys-use-cases" aria-label="Permalink to &quot;Journeys Use Cases:&quot;">​</a></h3><ul><li><p>Leverage your website to drive new downloads.</p></li><li><p>Direct/deferred deep link users to relevant in-app content they were viewing on web.</p></li><li><p>Personalized banners and interstitials by targeting based on web-behavior.</p><ul><li>Visitor from organic search</li><li>Visitor from email campaign</li><li>High-intent repeat visitor</li><li>Existing app user on website</li></ul></li></ul><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li>User clicks Branch Journeys banner while viewing web content.</li><li>App opens or user is taken to App/Play Store to download the app.</li><li>User is taken to app content they were viewing on web</li></ol><p>.png &quot;Screen Shot 2021-09-28 at 2.45.05 PM.png&quot;)</p><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>The Journeys feature is available as part of our Engagement product. Learn more on our <a href="./packaging.html">pricing</a> page.</p><h2 id="integration-guide" tabindex="-1">Integration Guide <a class="header-anchor" href="#integration-guide" aria-label="Permalink to &quot;Integration Guide&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Developer Required</p><p>Developers knowledgeable with APIs, Web, and Mobile Development are required.</p></div><h4 id="_1-implement-the-branch-mobile-sdks-to-your-mobile-app" tabindex="-1">1. Implement the Branch Mobile SDKs to your mobile app. <a class="header-anchor" href="#_1-implement-the-branch-mobile-sdks-to-your-mobile-app" aria-label="Permalink to &quot;1. Implement the Branch Mobile SDKs to your mobile app.&quot;">​</a></h4><p>Please visit our <a href="./docs.html">Developers Hub</a> to implement the Branch SDK on both iOS and Android.</p><h4 id="_2-implement-the-branch-web-sdk-to-your-website" tabindex="-1">2. Implement the Branch Web SDK to your website. <a class="header-anchor" href="#_2-implement-the-branch-web-sdk-to-your-website" aria-label="Permalink to &quot;2. Implement the Branch Web SDK to your website.&quot;">​</a></h4><p>Please visit our <a href="./web-sdk-overview.html">Web SDK docs</a> to implement the Branch Web SDK.</p><p>You can also implement the Branch Web SDK through your preferred Tag Manager (ex. Adobe, Google Tag Manager, Tealium, etc.).</p><h4 id="_3-create-journeys-banners-or-interstitials" tabindex="-1">3. Create Journeys Banners or Interstitials <a class="header-anchor" href="#_3-create-journeys-banners-or-interstitials" aria-label="Permalink to &quot;3. Create Journeys Banners or Interstitials&quot;">​</a></h4><p>Follow our guide on <a href="./create-journey-banner-or-interstitial.html">creating Journeys Banners or Interstitials</a>.</p><p>.png &quot;Screen Shot 2021-09-28 at 3.24.37 PM.png&quot;)</p><h4 id="_4-test-your-journeys" tabindex="-1">4. Test your Journeys <a class="header-anchor" href="#_4-test-your-journeys" aria-label="Permalink to &quot;4. Test your Journeys&quot;">​</a></h4><p>Test your Journeys banner or interstitial by placing a web URL that is initializing the Branch Web SDK to see the banner in action!</p><p>.png &quot;Screen Shot 2021-09-28 at 3.19.51 PM.png&quot;)</p>',23)])])}const d=a(i,[["render",n]]);export{b as __pageData,d as default};
